#!/usr/bin/env bash
# Inject skill routing table and session continuity instructions at session start.

cat <<'ROUTE'
{"additionalContext": "justin-tools: 24 graph-native skills. SeleneDB required. Suggest manual skills when you see the user working on a matching task.\n\nPlanning: feature-design, research, debate, plan-verify (auto)\nBuilding: modularize, refactor, code-standards (auto)\nDebugging: debug (auto), perf-profile, incident-response\nReview & Security: deep-review (auto), safety-checks (auto), dep-audit (auto)\nReleasing: release-prep, requirements-trace\nTracking: milestone-tracking (auto), deferred-tracking (auto), session-tracker (auto), commit-workflow (background)\nDocumentation: graph-docs, project-onboard\nBackground: notes (auto-annotate), skill-guide\n\nSession continuity: Query for recent session context before the first substantive task:\n  MATCH (s:Session) WHERE s.project = '<project>' AND s.summary IS NOT NULL RETURN s.skill, s.summary, s.next_steps, s.outcome, s.date ORDER BY s.date DESC LIMIT 3\nIf results exist, briefly note what was worked on recently. Do not present this as a formal report — just weave it naturally into your awareness.\n\nFor detailed routing: /justin-tools:skill-guide"}
ROUTE
